"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([[587530],{584174:s=>{s.exports=JSON.parse('{"tag":{"label":"ghost","permalink":"/dst-api-webdocs/docs/tags/ghost","allTagsPath":"/dst-api-webdocs/docs/tags","count":25,"items":[{"id":"game-scripts/prefabs/abigail","title":"Abigail","description":"Manages Abigail, Wendy\'s ghost companion, including combat behavior, leadership, buff application, transformation states, and interaction with player-bond mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/abigail"},{"id":"game-scripts/prefabs/abigail_flower","title":"Abigail Flower","description":"Manages the ghostly bond-based summoned flower item that provides spell commands to ghostly friends and updates visual state based on bond level and proximity.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/abigail_flower"},{"id":"game-scripts/brains/abigailbrain","title":"Abigailbrain","description":"Controls the behavior tree logic for Abigail, determining her movement, combat, and social actions based on leader proximity, mode (defensive/aggressive), and environmental context.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/abigailbrain"},{"id":"game-scripts/components/avengingghost","title":"Avengingghost","description":"Manages the avenging ghost state for Wendy, increasing damage over time while in ghost form if a nearby player has the \'wendy_avenging_ghost\' skill activated.","permalink":"/dst-api-webdocs/docs/game-scripts/components/avengingghost"},{"id":"game-scripts/scenarios/chest_ghosts","title":"Chest Ghosts","description":"A scenario script that modifies chest behavior to spawn ghosts and drain sanity when opened.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/chest_ghosts"},{"id":"game-scripts/components/decoratedgrave_ghostmanager","title":"Decoratedgrave Ghostmanager","description":"Manages the spawning, tracking, and despawning of grave guard ghosts for Wendy\'s skill-related grave mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/components/decoratedgrave_ghostmanager"},{"id":"game-scripts/scenarios/eyebone_ghost","title":"Eyebone Ghost","description":"Manages the spawning of ghosts on nearby graves when an eyebone item is picked up during a scenario.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/eyebone_ghost"},{"id":"game-scripts/prefabs/ghost","title":"Ghost","description":"Manages the ghost entity\'s behavior, including its aura damage, combat targeting, sanity effects, and tethering to a gravestone.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ghost"},{"id":"game-scripts/components/ghostbabysitter","title":"Ghostbabysitter","description":"Manages the tracking and lifecycle of ghosts being watched over by an entity, handling state tags and persistence.","permalink":"/dst-api-webdocs/docs/game-scripts/components/ghostbabysitter"},{"id":"game-scripts/prefabs/ghostcommand_defs","title":"Ghostcommand Defs","description":"Defines the structure and logic for Wendy\u2019s ghost command spells, including unsummon, behaviour commands, and skill-enabled abilities.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ghostcommand_defs"},{"id":"game-scripts/components/ghostgestalter","title":"Ghostgestalter","description":"Manages activation flags and mutation logic for ghost entities in the world.","permalink":"/dst-api-webdocs/docs/game-scripts/components/ghostgestalter"},{"id":"game-scripts/prefabs/ghostly_elixirs","title":"Ghostly Elixirs","description":"Creates consumable ghostly elixir items and their associated debuff components that apply temporary buffs to targets upon use.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/ghostly_elixirs"},{"id":"game-scripts/components/ghostlybond","title":"GhostlyBond","description":"Manages a spectral companion (ghost) tied to a player, handling summoning, recall, bonding progression, and state synchronization.","permalink":"/dst-api-webdocs/docs/game-scripts/components/ghostlybond"},{"id":"game-scripts/components/ghostlyelixirable","title":"Ghostlyelixirable","description":"Marks an entity as a ghostly elixir item by adding the `ghostlyelixirable` tag for use in gameplay logic.","permalink":"/dst-api-webdocs/docs/game-scripts/components/ghostlyelixirable"},{"id":"game-scripts/brains/graveguard_ghostbrain","title":"Graveguard Ghostbrain","description":"Controls the AI behavior of a ghost entity in DST, including following living targets, playful interaction with other ghosts, and periodic despawning.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/graveguard_ghostbrain"},{"id":"game-scripts/prefabs/gravestone","title":"Gravestone","description":"Manages the lifecycle, haunting mechanics, and ghost spawning behavior of a grave in the world, including seasonal flower decoration and upgrade stages.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/gravestone"},{"id":"game-scripts/scenarios/graveyard_ghosts","title":"Graveyard Ghosts","description":"Manages grave-related gameplay logic for spawning ghosts when graves are dug up, typically triggered during the Graveyard scenario.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/graveyard_ghosts"},{"id":"game-scripts/prefabs/lavaarena_abigail","title":"Lavaarena Abigail","description":"A prefabricated entity instance for a ghostly variant of Abigail used exclusively in the Lava Arena event.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/lavaarena_abigail"},{"id":"game-scripts/stategraphs/SGghost","title":"Sgghost","description":"Manages the state transitions and behavioral logic for the Ghost character entity, including idle, attack, knockback, death, and play states.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGghost"},{"id":"game-scripts/stategraphs/SGsmallghost","title":"Sgsmallghost","description":"Defines the state graph for the SmallGhost entity, governing its behavior, animations, and interactions such as idle states, quest progression, and toy-related actions.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGsmallghost"},{"id":"game-scripts/stategraphs/SGwilsonghost","title":"Sgwilsonghost","description":"Manages the state machine for Wilson\'s ghost form, handling transitions between idle, moving, talking, dying, and teleporting states in the Don\'t Starve Together game.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGwilsonghost"},{"id":"game-scripts/stategraphs/SGwilsonghost_client","title":"Sgwilsonghost Client","description":"Manages client-side state transitions and movement prediction for Wilson\'s ghost form, synchronizing animation, locomotion, and action previewing with server confirmation.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGwilsonghost_client"},{"id":"game-scripts/prefabs/smallghost","title":"Smallghost","description":"Manages the quest logic, behavior, and environmental feedback for the small ghost character in DST, including toy collection, player linking, and hot/cold hunt cues.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/smallghost"},{"id":"game-scripts/brains/smallghostbrain","title":"Smallghostbrain","description":"AI brain controlling small ghost behavior, including following leader, locating lost toys, hinting with jump-in actions, and avoiding combat.","permalink":"/dst-api-webdocs/docs/game-scripts/brains/smallghostbrain"},{"id":"game-scripts/prefabs/wendy","title":"Wendy","description":"Implements Wendy\u2019s unique gameplay mechanics, including Abigail the ghostly friend, sanity aura adjustments during Sisturn events, and bonding progression.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/wendy"}],"unlisted":false}}')}}]);